    public static int solveQuery(int start, int end, int[] arr) {
        // Use a HashMap to store frequencies, similar to Python's dictionary
        Map<Integer, Integer> frequency = new HashMap<>();
        // Iterate through the specified range [start, end] (inclusive)
        for (int i = start; i <= end; i++) {
            // Get the current element
            int element = arr[i];
            // Increment its frequency. If the element is not already in the map,
            // getOrDefault returns 0, so it will be initialized to 1.
            frequency.put(element, frequency.getOrDefault(element, 0) + 1);
        }
        int count = 0;
        // Iterate over the entries (key-value pairs) in the frequency map
        for (Map.Entry<Integer, Integer> entry : frequency.entrySet()) {
            int key = entry.getKey();   // The element itself
            int value = entry.getValue(); // Its frequency
            // Check if the element's value is equal to its frequency
            if (key == value) {
                count++;
            }
        }
        return count;
    }

