static     public boolean check(String s1, String s2) {
        int n = s1.length();
        int m = s2.length();
        // dp[i][j] will be true if the first i characters of s1 can form the first j characters of s2
        boolean[][] dp = new boolean[n + 1][m + 1];
        // Base case: an empty s1 can form an empty s2
        dp[0][0] = true;
        // Iterate through s1 characters
        for (int i = 0; i < n; i++) {
            // Iterate through s2 characters (including the state before any s2 characters)
            for (int j = 0; j <= m; j++) {
                // If the current state dp[i][j] is reachable (true)
                if (dp[i][j]) {
                    // Option 1: Match s1[i] with s2[j]
                    // This is possible if:
                    // 1. j is within s2 bounds (i.e., s2[j] exists)
                    // 2. The uppercase version of s1[i] matches s2[j]
                    if (j < m && Character.toUpperCase(s1.charAt(i)) == s2.charAt(j)) {
                        dp[i + 1][j + 1] = true;
                    }
                    // Option 2: Skip s1[i] (only if s1[i] is a lowercase character)
                    // This is possible if:
                    // 1. s1[i] is NOT an uppercase character
                    if (!Character.isUpperCase(s1.charAt(i))) {
                        dp[i + 1][j] = true;
                    }
                }
            }
        }
        // The final result is whether the entire s1 can form the entire s2
        return dp[n][m];
    }

