    public static boolean checkIsAP(int[] arr, int n) {
        // An array with 0 or 1 element is always considered an Arithmetic Progression.
        // The original Python code only explicitly checks for n == 1.
        // If n < 2, there are not enough elements to determine a common difference,
        // so it's trivially an AP.
        if (n <= 1) {
            return true;
        }
        // To correctly check for an AP, the elements must be in order.
        // Sorting the array ensures that we are checking the difference
        // between logically consecutive terms of a potential AP.
        Arrays.sort(arr);
        // Calculate the common difference using the first two elements
        // after sorting. We can safely access arr[0] and arr[1] because
        // we've already checked that n >= 2.
        int d = arr[1] - arr[0];
        // Iterate from the third element (index 2) up to the end of the array.
        // Check if the difference between the current element and its
        // preceding element is equal to the common difference 'd'.
        for (int i = 2; i < n; i++) {
            if (arr[i] - arr[i - 1] != d) {
                // If any difference is not equal to 'd', it's not an AP.
                return false;
            }
        }
        // If the loop completes without finding any discrepancies,
        // it means all consecutive differences are equal, so it's an AP.
        return true;
    }

