    public static String decimalToBinary(double num, int k_prec) {
        StringBuilder binary = new StringBuilder();
        // Separate integral and fractional parts
        int integral = (int) num;
        double fractional = num - integral;
        // Convert integral part to binary
        // Handle the case where integral is 0 initially (e.g., for 0.625)
        if (integral == 0) {
            binary.append("0");
        } else {
            while (integral > 0) {
                int rem = integral % 2;
                binary.append(rem);
                integral /= 2;
            }
            // Reverse the integral part's binary string
            binary.reverse();
        }
        // Append decimal point
        binary.append('.');
        // Convert fractional part to binary
        while (k_prec > 0) {
            fractional *= 2;
            int fractBit = (int) fractional;
            if (fractBit == 1) {
                fractional -= fractBit; // Remove the integer part (1)
                binary.append('1');
            } else {
                binary.append('0');
            }
            k_prec--;
        }
        return binary.toString();
    }

