    public static int KnapSack(int[] val, int[] wt, int n, int W) {
        // dp[j] will store the maximum value that can be obtained with a knapsack of capacity j.
        // Initialize dp array with size W + 1. In Java, int arrays are default-initialized to 0.
        int[] dp = new int[W + 1];
        // Iterate through each item
        for (int i = 0; i < n; i++) {
            // Iterate through the knapsack capacities from W down to 0
            // This reverse iteration is crucial for the 0/1 Knapsack problem
            // to ensure each item is considered only once (either included or not).
            for (int j = W; j >= 0; j--) {
                // If the current item's weight (wt[i]) can fit into the current capacity (j)
                if (j - wt[i] >= 0) {
                    // Option 1: Do not include the current item. The value remains dp[j].
                    // Option 2: Include the current item. The value would be val[i]
                    //           plus the maximum value achievable for the remaining capacity (j - wt[i]).
                    dp[j] = Math.max(dp[j], val[i] + dp[j - wt[i]]);
                }
                // If j - wt[i] < 0, it means the current item is too heavy for the current capacity j,
                // so we cannot include it. In this case, dp[j] remains unchanged (it holds the max value
                // achievable without this item for this capacity).
            }
        }
        // The maximum value for the knapsack with capacity W will be stored in dp[W].
        return dp[W];
    }

