    public static int gcd(int a, int b) {
        if (a == 0) {
            return b;
        }
        if (b == 0) {
            return a;
        }
        int k = 0;
        // Find common factors of 2
        while (((a | b) & 1) == 0) {
            a >>= 1; // a = a / 2
            b >>= 1; // b = b / 2
            k++;     // k = k + 1
        }
        // Remove factors of 2 from a (make a odd)
        while ((a & 1) == 0) {
            a >>= 1; // a = a / 2
        }
        // Now a is odd.
        // Loop until b becomes 0.
        while (b != 0) {
            // Remove factors of 2 from b (make b odd)
            while ((b & 1) == 0) {
                b >>= 1; // b = b / 2
            }
            // Ensure a <= b
            if (a > b) {
                int temp = a;
                a = b;
                b = temp;
            }
            // b = b - a (both a and b are odd, so b - a is even)
            b = (b - a);
        }
        // Restore common factors of 2
        return (a << k); // a * (2^k)
    }

