    public static double seriesSum(int n) {
        int i = 1;
        double res = 0.0;
        boolean sign = true; // Corresponds to Python's True
        while (n > 0) {
            n = n - 1; // or n--;
            if (sign) {
                sign = false; // Corresponds to Python's False
                // In Python 3, `/` performs float division.
                // In Java, for integer operands, it would be integer division.
                // We need to cast one operand to double to ensure float division.
                res = res + (double)(i + 1) / (i + 2);
                i = i + 2;
            } else {
                sign = true; // Corresponds to Python's True
                res = res - (double)(i + 1) / (i + 2);
                i = i + 2;
            }
        }
        return res;
    }

