static     public int sumofsquare(int n) {
        // Initialize a 2D array (equivalent to Python's list of lists)
        // C will store binomial coefficients (Pascal's Triangle)
        int[][] C = new int[n + 1][n + 1];
        // Populate the C array with binomial coefficients C(i, j)
        // This part builds Pascal's Triangle up to row 'n'
        for (int i = 0; i <= n; i++) {
            // The inner loop goes from j = 0 up to min(i, n).
            // Since j will never exceed i in Pascal's triangle, min(i, n)
            // can effectively be just 'i' for practical purposes in this loop,
            // as C[i][j] where j > i is 0 (or not calculated).
            // However, sticking to the Python's min(i, n) for direct translation:
            for (int j = 0; j <= Math.min(i, n); j++) {
                // Base cases for binomial coefficients: C(i, 0) = 1 and C(i, i) = 1
                if (j == 0 || j == i) {
                    C[i][j] = 1;
                } else {
                    // Recurrence relation: C(i, j) = C(i-1, j-1) + C(i-1, j)
                    C[i][j] = (C[i - 1][j - 1] + C[i - 1][j]);
                }
            }
        }
        // Calculate the sum of squares of binomial coefficients for row 'n'
        // This calculates C(n,0)^2 + C(n,1)^2 + ... + C(n,n)^2
        int sum = 0;
        for (int i = 0; i <= n; i++) {
            sum = sum + (C[n][i] * C[n][i]);
        }
        return sum;
    }

