static     public int offeringNumber(int n, int[] templeHeight) {
        int sum = 0;
        for (int i = 0; i < n; i++) {
            int left = 0;
            int right = 0;
            // Calculate 'left' offerings
            for (int j = i - 1; j >= 0; j--) {
                if (templeHeight[j] < templeHeight[j + 1]) {
                    left++;
                } else {
                    break;
                }
            }
            // Calculate 'right' offerings
            for (int j = i + 1; j < n; j++) {
                if (templeHeight[j] < templeHeight[j - 1]) {
                    right++;
                } else {
                    break;
                }
            }
            sum += Math.max(right, left) + 1;
        }
        return sum;
    }

