    public static int countUnique ( int [ ] [ ] mat , int n , int m ) {
        // Initialize rowsum and colsum arrays with zeros
        int [ ] rowsum = new int [ n ] ;
        int [ ] colsum = new int [ m ] ;
        // First pass: Calculate the count of non-zero elements for each row and column
        for ( int i = 0 ; i < n ; i ++ ) {
            for ( int j = 0 ; j < m ; j ++ ) {
                if ( mat [ i ] [ j ] != 0 ) {
                    rowsum [ i ] ++ ;
                    colsum [ j ] ++ ;
                }
            }
        }
        // Initialize unique count
        int uniquecount = 0 ;
        // Second pass: Count elements that are unique in their row AND column
        for ( int i = 0 ; i < n ; i ++ ) {
            for ( int j = 0 ; j < m ; j ++ ) {
                // An element is considered "unique" if:
                // 1. It is not zero itself.
                // 2. It is the only non-zero element in its row (rowsum[i] == 1).
                // 3. It is the only non-zero element in its column (colsum[j] == 1).
                if ( mat [ i ] [ j ] != 0 && rowsum [ i ] == 1 && colsum [ j ] == 1 ) {
                    uniquecount ++ ;
                }
            }
        }
        return uniquecount ;
    }

