    public static int CountWays(int n) {
        // Create an array (table) of size n + 1, initialized with zeros.
        // In Java, int arrays are automatically initialized to 0.
        int[] table = new int[n + 1];
        // Base case: There is one way to make a sum of 0 (by choosing nothing).
        table[0] = 1;
        // Iterate through possible "items" or "denominations" from 1 up to n-1.
        // The original Python `range(1, n)` means i goes from 1 up to n-1.
        for (int i = 1; i < n; i++) {
            // For each "item" i, iterate through possible "sums" from i up to n.
            // The original Python `range(i, n + 1)` means j goes from i up to n.
            for (int j = i; j <= n; j++) {
                // The number of ways to make sum `j` is increased by the number of
                // ways to make sum `j - i` (representing choosing item `i`).
                table[j] += table[j - i];
            }
        }
        // The result is the number of ways to make sum `n`.
        return table[n];
    }

